import { Component, signal } from '@angular/core';
import { AXLineChartComponent } from '@acorex/charts/line-chart';
import { AXLineChartValue } from '@acorex/charts/line-chart';
import { AXLineChartOption } from '@acorex/charts/line-chart';
import { AXLineChartPointClickEvent } from '@acorex/charts/line-chart';

@Component({
  template: `
    <div class="showcase-container">
      <h2>Interactive Line Chart</h2>
      <ax-line-chart 
        [data]="showcaseData()" 
        [options]="showcaseOptions()"
        (pointClick)="onPointClick($event)"
      />
      <div class="chart-info">
        <p>Click on data points to interact with the chart</p>
      </div>
    </div>
  `,
  imports: [AXLineChartComponent],
  styles: [`
    .showcase-container {
      padding: 2rem;
      background: var(--ax-sys-color-lightest-surface);
      border-radius: 8px;
    }
    .chart-info {
      margin-top: 1rem;
      text-align: center;
      color: var(--ax-sys-color-on-lightest-surface);
    }
  `]
})
export class LineChartShowcaseComponent {
  showcaseData = signal<AXLineChartValue>([
    {
      id: 'revenue',
      label: 'Revenue',
      lineColor: '#3498db',
      fillColor: 'rgba(52, 152, 219, 0.2)',
      data: [
        { x: 'Jan', y: 12000 },
        { x: 'Feb', y: 15000 },
        { x: 'Mar', y: 18000 },
        { x: 'Apr', y: 16000 },
        { x: 'May', y: 22000 },
        { x: 'Jun', y: 25000 }
      ]
    },
    {
      id: 'expenses',
      label: 'Expenses',
      lineColor: '#e74c3c',
      fillColor: 'rgba(231, 76, 60, 0.2)',
      data: [
        { x: 'Jan', y: 8000 },
        { x: 'Feb', y: 9500 },
        { x: 'Mar', y: 11000 },
        { x: 'Apr', y: 10500 },
        { x: 'May', y: 12000 },
        { x: 'Jun', y: 13000 }
      ]
    }
  ]);

  showcaseOptions = signal<AXLineChartOption>({
    showXAxis: true,
    showYAxis: true,
    showGrid: true,
    xAxisLabel: 'Month',
    yAxisLabel: 'Amount ($)',
    width: 600,
    height: 400,
    lineWidth: 3,
    showPoints: true,
    pointRadius: 6,
    smoothLine: true,
    fillArea: true,
    fillOpacity: 20,
    showCrosshair: true,
    showTooltip: true,
    animationDuration: 1500,
    animationEasing: 'ease-in-out'
  });

  onPointClick(event: AXLineChartPointClickEvent): void {
    console.log('Point clicked:', event.series.label, event.point);
  }
}
